//! Principal Component Analysis (PCA) implementation
//!
//! This module provides PCA functionality for confound variable processing,
//! matching the behavior of R's prcomp function.

use nalgebra::{DMatrix, DVector, SVD};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

use crate::error::{BidsError, Result};

/// PCA processor for confound variables
#[derive(Debug, Clone)]
pub struct PcaProcessor {
    /// Data matrix (observations x variables)
    pub data: DMatrix<f64>,
    /// Variable names
    pub variable_names: Vec<String>,
    /// Whether to center the data
    pub center: bool,
    /// Whether to scale the data
    pub scale: bool,
}

/// Result of PCA computation
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PcaResult {
    /// Principal component scores (observations x components)
    pub scores: Vec<Vec<f64>>,
    /// Principal component loadings (variables x components)
    pub loadings: Vec<Vec<f64>>,
    /// Explained variance for each component
    pub explained_variance: Vec<f64>,
    /// Explained variance ratio for each component
    pub explained_variance_ratio: Vec<f64>,
    /// Cumulative explained variance ratio
    pub cumulative_variance_ratio: Vec<f64>,
    /// Standard deviations of principal components
    pub standard_deviations: Vec<f64>,
    /// Means of original variables (if centered)
    pub means: Vec<f64>,
    /// Standard deviations of original variables (if scaled)
    pub scales: Vec<f64>,
    /// Variable names
    pub variable_names: Vec<String>,
}

impl PcaProcessor {
    /// Create a new PCA processor
    pub fn new(data: DMatrix<f64>, variable_names: Vec<String>) -> Result<Self> {
        if data.ncols() != variable_names.len() {
            return Err(BidsError::analysis_error(
                "Number of variables must match number of variable names",
                None,
            ));
        }

        Ok(Self {
            data,
            variable_names,
            center: true,
            scale: true,
        })
    }

    /// Create PCA processor from a vector of variable data
    pub fn from_variables(variables: Vec<(String, Vec<f64>)>) -> Result<Self> {
        if variables.is_empty() {
            return Err(BidsError::analysis_error("No variables provided", None));
        }

        let n_obs = variables[0].1.len();
        let n_vars = variables.len();

        // Check that all variables have the same number of observations
        for (name, data) in &variables {
            if data.len() != n_obs {
                return Err(BidsError::analysis_error(
                    format!("Variable '{}' has {} observations, expected {}", name, data.len(), n_obs),
                    None,
                ));
            }
        }

        // Create data matrix
        let mut data_matrix = DMatrix::zeros(n_obs, n_vars);
        let mut variable_names = Vec::with_capacity(n_vars);

        for (j, (name, data)) in variables.into_iter().enumerate() {
            variable_names.push(name);
            for (i, value) in data.into_iter().enumerate() {
                data_matrix[(i, j)] = value;
            }
        }

        Self::new(data_matrix, variable_names)
    }

    /// Create PCA processor from a HashMap of confound variables
    pub fn from_confound_map(confounds: HashMap<String, Vec<f64>>) -> Result<Self> {

