pub fn from_confound_map(confounds: HashMap<String, Vec<f64>>) -> Result<Self> {
    let variables: Vec<(String, Vec<f64>)> = confounds.into_iter().collect();
    Self::from_variables(variables)
}

/// Set whether to center the data
pub fn center(mut self, center: bool) -> Self {
    self.center = center;
    self
}

/// Set whether to scale the data
pub fn scale(mut self, scale: bool) -> Self {
    self.scale = scale;
    self
}

/// Compute PCA
pub fn compute(&self) -> Result<PcaResult> {
    let mut data = self.data.clone();
    let mut means = vec![0.0; self.data.ncols()];
    let mut scales = vec![1.0; self.data.ncols()];

    // Center the data
    if self.center {
        for j in 0..data.ncols() {
            let col = data.column(j);
            let mean = col.mean();
            means[j] = mean;

            for i in 0..data.nrows() {
                data[(i, j)] -= mean;
            }
        }
    }

    // Scale the data
    if self.scale {
        for j in 0..data.ncols() {
            let col = data.column(j);
            let variance = col.map(|x| x.powi(2)).sum() / (data.nrows() - 1) as f64;
            let std_dev = variance.sqrt();

            if std_dev < f64::EPSILON {
                return Err(BidsError::math_error(
                    format!("Variable '{}' has zero variance", self.variable_names[j]),
                    None,
                ));
            }

            scales[j] = std_dev;

            for i in 0..data.nrows() {
                data[(i, j)] /= std_dev;
            }
        }
    }

    // Perform SVD
    let svd = SVD::new(data.clone(), true, true);

    let u = svd.u.ok_or_else(|| {
        BidsError::math_error("SVD failed to compute U matrix", None)
    })?;

    let v_t = svd.v_t.ok_or_else(|| {
        BidsError::math_error("SVD failed to compute V^T matrix", None)
    })?;

    let singular_values = svd.singular_values;
    let n_components = singular_values.len();

    // Calculate explained variance
    let total_variance = singular_values.iter().map(|s| s.powi(2)).sum::<f64>();
    let explained_variance: Vec<f64> = singular_values
        .iter()
        .map(|s| s.powi(2) / (data.nrows() - 1) as f64)
        .collect();

    let explained_variance_ratio: Vec<f64> = explained_variance
        .iter()
        .map(|var| var / total_variance * (data.nrows() - 1) as f64)
        .collect();

    let cumulative_variance_ratio: Vec<f64> = explained_variance_ratio
        .iter()
        .scan(0.0, |acc, &x| {
            *acc += x;
            Some(*acc)
        })
        .collect();

    // Calculate standard deviations
    let standard_deviations: Vec<f64> = explained_variance
        .iter()
        .map(|var| var.sqrt())
        .collect();

    // Extract scores (principal components)
    let scores_matrix = &u * DMatrix::from_diagonal(&singular_values);

