use criterion::{black_box, criterion_group, criterion_main, Criterion};
use bids_rust::{BidsProject};
use bids_rust::analysis::pca::PcaProcessor;
use std::path::Path;
use tempfile::TempDir;
use std::fs;
use std::collections::HashMap;

fn create_benchmark_dataset(n_subjects: usize, n_sessions: usize, n_runs: usize) -> TempDir {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Create dataset_description.json
    let dataset_desc = r#"{
        "Name": "Benchmark Dataset",
        "BIDSVersion": "1.6.0"
    }"#;
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();

    // Create files for each subject/session/run
    for sub in 1..=n_subjects {
        for ses in 1..=n_sessions {
            let dir_path = root_path
                .join(format!("sub-{:02}", sub))
                .join(format!("ses-{:02}", ses))
                .join("func");
            fs::create_dir_all(&dir_path).unwrap();

            for run in 1..=n_runs {
                // Create functional scan
                let filename = format!(
                    "sub-{:02}_ses-{:02}_task-benchmark_run-{}_bold.nii.gz",
                    sub, ses, run
                );
                fs::write(dir_path.join(&filename), b"dummy").unwrap();

                // Create JSON sidecar
                let json_name = filename.replace(".nii.gz", ".json");
                fs::write(
                    dir_path.join(json_name),
                    r#"{"RepetitionTime": 2.0}"#
                ).unwrap();

                // Create events file
                let events_name = format!(
                    "sub-{:02}_ses-{:02}_task-benchmark_run-{}_events.tsv",
                    sub, ses, run
                );
                fs::write(
                    dir_path.join(events_name),
                    "onset\tduration\ttrial_type\n0\t2\tstim\n"
                ).unwrap();
            }
        }
    }

    temp_dir
}

fn benchmark_project_creation(c: &mut Criterion) {
    let _temp_dir = create_benchmark_dataset(10, 2, 3);
    let path = _temp_dir.path();

    c.bench_function("project_creation", |b| {
        b.iter(|| {
            let project = BidsProject::new(black_box(path)).unwrap();
            black_box(project);
        });
    });
}

fn benchmark_filename_parsing(c: &mut Criterion) {
    let filenames = vec![
        "sub-01_ses-pre_task-rest_run-1_bold.nii.gz",
        "sub-01_ses-pre_task-rest_space-MNI152NLin2009cAsym_desc-preproc_bold.nii.gz",
        "sub-01_ses-pre_task-rest_desc-confounds_timeseries.tsv",
        "sub-01_ses-pre_T1w.nii.gz",
    ];

    c.bench_function("filename_parsing", |b| {
        b.iter(|| {
            for filename in &filenames {
                let parsed = parse_bids_filename(black_box(filename)).unwrap();
                black_box(parsed);
            }
        });
    });
}

fn benchmark_file_search(c: &mut Criterion) {
    let _temp_dir = create_benchmark_dataset(20, 2, 3);
    let project = BidsProject::new(_temp_dir.path()).unwrap();

    c.bench_function("search_all_files", |b| {
        b.iter(|| {
            let files = project.search_files()
                .execute()
                .unwrap();
            black_box(files);
        });
    });

    c.bench_function("search_filtered", |b| {
        b.iter(|| {
            let files = project.search_files()
                .subject("05")
                .session("01")
                .suffix("bold")
                .execute()
                .unwrap();
            black_box(files);
        });
    });
}

fn benchmark_entity_extraction(c: &mut Criterion) {
    let _temp_dir = create_benchmark_dataset(10, 2, 2);
    let project = BidsProject::new(_temp_dir.path()).unwrap();

    c.bench_function("get_participants", |b| {
        b.iter(|| {
            let participants = project.participants();
            black_box(participants);
        });
    });

    c.bench_function("get_sessions", |b| {
        b.iter(|| {
            let sessions = project.sessions();
            black_box(sessions);
        });
    });

    c.bench_function("get_tasks", |b| {
        b.iter(|| {
            let tasks = project.tasks();
            black_box(tasks);
        });
    });
}

fn benchmark_summary_generation(c: &mut Criterion) {
    let _temp_dir = create_benchmark_dataset(15, 2, 3);
    let project = BidsProject::new(_temp_dir.path()).unwrap();

    c.bench_function("project_summary", |b| {
        b.iter(|| {
            let summary = project.summary();
            black_box(summary);
        });
    });
}

fn benchmark_pca_small(c: &mut Criterion) {
    // Create small confound data (100 timepoints, 20 variables)
    let mut confounds = HashMap::new();
    for i in 0..20 {
        let data: Vec<f64> = (0..100).map(|j| (j as f64 * (i + 1) as f64).sin()).collect();
        confounds.insert(format!("confound_{}", i), data);
    }

    c.bench_function("pca_small_dataset", |b| {
        b.iter(|| {
            let processor = PcaProcessor::from_confound_map(confounds.clone()).unwrap();
            let result = processor.compute().unwrap();
            black_box(result);
        });
    });
}

fn benchmark_pca_medium(c: &mut Criterion) {
    // Create medium confound data (500 timepoints, 50 variables)
    let mut confounds = HashMap::new();
    for i in 0..50 {
        let data: Vec<f64> = (0..500).map(|j| (j as f64 * (i + 1) as f64 / 50.0).cos()).collect();
        confounds.insert(format!("confound_{}", i), data);
    }

    c.bench_function("pca_medium_dataset", |b| {
        b.iter(|| {
            let processor = PcaProcessor::from_confound_map(confounds.clone()).unwrap();
            let result = processor.compute().unwrap();
            black_box(result);
        });
    });
}

fn benchmark_pca_large(c: &mut Criterion) {
    // Create large confound data (1000 timepoints, 100 variables)
    let mut confounds = HashMap::new();
    for i in 0..100 {
        let data: Vec<f64> = (0..1000).map(|j| {
            (j as f64 * (i + 1) as f64 / 100.0).sin() + 
            (j as f64 * (i + 1) as f64 / 200.0).cos()
        }).collect();
        confounds.insert(format!("confound_{}", i), data);
    }

    c.bench_function("pca_large_dataset", |b| {
        b.iter(|| {
            let processor = PcaProcessor::from_confound_map(confounds.clone()).unwrap();
            let result = processor.compute().unwrap();
            black_box(result);
        });
    });
}

criterion_group!(
    benches,
    benchmark_project_creation,
    benchmark_filename_parsing,
    benchmark_file_search,
    benchmark_entity_extraction,
    benchmark_summary_generation,
    benchmark_pca_small,
    benchmark_pca_medium,
    benchmark_pca_large
);
criterion_main!(benches);

