    /// Compute PCA with memory optimization for large datasets
    /// Uses truncated computation for datasets with many variables
    pub fn compute_optimized(&self) -> Result<PcaResult> {
        // For small datasets, use regular computation
        if self.data.ncols() <= 1000 && self.data.nrows() <= 10000 {
            return self.compute();
        }

        // For large datasets, compute only top components
        let n_components = if self.data.ncols() > 1000 {
            (self.data.ncols() / 10).max(50).min(200)
        } else {
            // If many observations but few variables, still limit components
            self.data.ncols().min(100)
        };

        self.compute_n_components(n_components)
    }

    /// Check if the dataset is large enough to benefit from optimization
    pub fn should_optimize(&self) -> bool {
        self.data.ncols() > 1000 || self.data.nrows() > 10000
    }
}

