    let mut file = File::create(&parsing_test_path)?;

    writeln!(file, "filename,parsed_successfully,error_message")?;

    for filename in test_filenames {
        match parse_filename(filename) {
            Ok(_parsed) => {
                writeln!(file, "\"{}\",true,\"\"", filename)?;
            }
            Err(e) => {
                writeln!(file, "\"{}\",false,\"{}\"", filename, e)?;
            }
        }
    }

